INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 7, 0.0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "キャル", 1, 0, -363.0, 0.0, 7001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 7, 0.0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "コッコロ", 1, 0, -363.0, 0.0, 7002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 7, 0.0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "ペコリーヌ", 1, 0, -363.0, 0.0, 7003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 10, 0.0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", "ペコリーヌ", 1, 0, -363.0, 0.0, 10001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 10, 0.0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "キャル", 1, 0, -363.0, 0.0, 10002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 10, 0.0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "コッコロ", 1, 0, -363.0, 0.0, 10003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 10, 0.0, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "シェフィ", 1, 0, -363.0, 0.0, 10004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 12, 0.0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "ペコリーヌ", 1, 0, -416.5, 0.0, 12001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 13, 0.0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "キャル", 1, 0, -363.0, 0.0, 13001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 13, 0.0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "コッコロ", 1, 0, -363.0, 0.0, 13002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 13, 0.0, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "シェフィ", 1, 0, -363.0, 0.0, 13003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 13, 0.0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "ペコリーヌ", 1, 0, -363.0, 0.0, 13004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 14, 0.0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "コッコロ", 1, 0, -363.0, 0.0, 14001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 14, 0.0, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "シェフィ", 1, 0, -363.0, 0.0, 14002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 14, 0.0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "ペコリーヌ", 1, 0, -363.0, 0.0, 14003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 14, 0.0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "キャル", 1, 0, -363.0, 0.0, 14004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 15, 0.0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "コッコロ", 1, 0, -470.0, 0.0, 15001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 16, 0.0, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "シェフィ", 1, 0, -363.0, 0.0, 16001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 16, 0.0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "ペコリーヌ", 1, 0, -363.0, 0.0, 16002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 16, 0.0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "キャル", 1, 0, -363.0, 0.0, 16003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 16, 0.0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "コッコロ", 1, 0, -363.0, 0.0, 16004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 17, 0.0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "コッコロ", 1, 0, -363.0, 0.0, 17002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 25, 0.0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "キャル", 1, 0, -363.0, 0.0, 17004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 25, 0.0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "コッコロ", 1, 0, -363.0, 0.0, 17005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 25, 0.0, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "シェフィ", 1, 0, -363.0, 0.0, 17006);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 25, 0.0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "ペコリーヌ", 1, 0, -363.0, 0.0, 17007);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 18, 0.0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "カリン", 1, 0, -363.0, 0.0, 18001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 18, 0.0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "カリン", 2, 0, -363.0, 0.0, 18002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 19, 0.0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "カリン", 3, 0, -470.0, 0.0, 19001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 19, 0.0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "カリン", 4, 0, -470.0, 0.0, 19002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 20, 0.0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "カリン", 5, 0, -470.0, 0.0, 20001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 20, 0.0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "カリン", 6, 0, -470.0, 0.0, 20002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 21, 0.0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "キャル", 1, 0, -363.0, 0.0, 21001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 21, 0.0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "コッコロ", 1, 0, -363.0, 0.0, 21002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 21, 0.0, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "シェフィ", 1, 0, -363.0, 0.0, 21003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 21, 0.0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "ペコリーヌ", 1, 0, -363.0, 0.0, 21004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 22, 0.0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "カリン", 1, 0, -430.0, 0.0, 22001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 22, 0.0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "カリン", 2, 0, -430.0, 0.0, 22002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 23, 0.0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "カリン", 3, 0, -430.0, 0.0, 23001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 23, 0.0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "カリン", 4, 0, -430.0, 0.0, 23002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109001, 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "エリコ（バレンタイン）", 1, 10011, -385.0, 4.08, 24001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109001, 1, "2030/12/17 14:59:59", 2, 24, 8.0, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "エリコ（バレンタイン）", 2, 10011, -385.0, 5.0, 24002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109001, 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "エリコ（バレンタイン）", 3, 10011, -385.0, 10.11, 24003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109001, 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "エリコ（バレンタイン）", 4, 10011, -385.0, 4.0, 24004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109001, 1, "2030/12/17 14:59:59", 2, 24, 8.0, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "エリコ（バレンタイン）", 5, 10011, -385.0, 6.0, 24005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109002, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "エリコ（バレンタイン）", 6, 10011, 0.0, 0.0, 24006);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109002, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "エリコ（バレンタイン）", 7, 10011, 0.0, 0.0, 24007);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109002, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "エリコ（バレンタイン）", 8, 10011, 0.0, 0.0, 24008);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109002, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "エリコ（バレンタイン）", 9, 10011, 0.0, 0.0, 24009);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109002, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "エリコ（バレンタイン）", 10, 10011, 0.0, 0.0, 24010);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109101, 1, "2030/12/17 14:59:59", 2, 24, 8.0, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "シズル（バレンタイン）", 1, 10011, -385.0, 2.12, 24011);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109101, 5, "2030/12/17 14:59:59", 2, 24, 8.0, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "シズル（バレンタイン）", 2, 10011, -385.0, 4.19, 24012);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109101, 2, "2030/12/17 14:59:59", 4, 24, 8.0, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "シズル（バレンタイン）", 3, 10011, -385.0, 2.3, 24013);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109102, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "シズル（バレンタイン）", 4, 10011, 0.0, 0.0, 24014);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109101, 5, "2030/12/17 14:59:59", 2, 24, 8.0, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "シズル（バレンタイン）", 5, 10011, -385.0, 5.23, 24015);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109102, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "シズル（バレンタイン）", 6, 10011, 0.0, 0.0, 24016);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109101, 1, "2030/12/17 14:59:59", 2, 24, 8.0, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "シズル（バレンタイン）", 7, 10011, -385.0, 5.01, 24017);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109102, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "シズル（バレンタイン）", 8, 10011, 0.0, 0.0, 24018);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109102, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "シズル（バレンタイン）", 9, 10011, 0.0, 0.0, 24019);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 109102, 1, "2030/12/17 14:59:59", 1, 24, 0.0, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "シズル（バレンタイン）", 10, 10011, 0.0, 0.0, 24020);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 26, 0.0, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "シェフィ", 1, 0, -363.0, 0.0, 26001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 26, 0.0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "ペコリーヌ", 1, 0, -363.0, 0.0, 26002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 26, 0.0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "キャル", 1, 0, -363.0, 0.0, 26003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 26, 0.0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "コッコロ", 1, 0, -363.0, 0.0, 26004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 2, "2030/12/17 14:59:59", 1, 27, 0.0, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "シェフィ", 1, 0, -363.0, 0.0, 27001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 27, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "ペコリーヌ", 1, 0, -363.0, 0.0, 27002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 27, 0.0, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", "キャル", 1, 0, -363.0, 0.0, 27003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 27, 0.0, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", "コッコロ", 1, 0, -363.0, 0.0, 27004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 28, 0.0, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", "カリン", 1, 0, -363.0, 0.0, 28001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 28, 0.0, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", "カリン", 2, 0, -363.0, 0.0, 28002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 29, 0.0, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", "カリン", 3, 0, -409.0, 0.0, 29001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 29, 0.0, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", "カリン", 4, 0, -409.0, 0.0, 29002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 30, 0.0, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", "カリン", 5, 0, -409.0, 0.0, 30001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 30, 0.0, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", "カリン", 6, 0, -409.0, 0.0, 30002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/10/31 12:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 31, 0.0, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", "カリン", 7, 0, -409.0, 0.0, 31001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/10/31 12:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 31, 0.0, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", "カリン", 8, 0, -409.0, 0.0, 31002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 190801, 1, "2020/01/04 4:59:59", 1, 32, 0.0, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", "カリン", 1, 0, -409.0, 0.0, 32001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 190801, 1, "2020/01/04 4:59:59", 1, 32, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", 2, 0, -409.0, 0.0, 32002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 190801, 1, "2020/01/04 4:59:59", 1, 33, 0.0, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", "カリン", 3, 0, -409.0, 0.0, 33001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 190801, 1, "2020/01/04 4:59:59", 1, 33, 0.0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", 4, 0, -409.0, 0.0, 33002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2020/01/04 5:00:00", 190801, 1, "2020/01/10 11:59:59", 1, 34, 0.0, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", "カリン", 5, 0, -409.0, 0.0, 34001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2020/01/04 5:00:00", 190801, 1, "2020/01/10 11:59:59", 1, 34, 0.0, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", "カリン", 6, 0, -409.0, 0.0, 34002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 2, 38, 0.0, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", "ペコリーヌ", 1, 0, -458.0, 5.3, 38001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 2, 38, 0.0, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", "ペコリーヌ", 2, 0, -458.0, 6.5, 38002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2020/04/01", 105801, 3, "2020/04/08 23:59:59", 3, 39, 9999.0, "", "ペコリーヌ", 0, 0, 9999.0, 0.0, 39005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 190801, 1, "2030/12/17 14:59:59", 1, 40, 0.0, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", "カリン", 2, 0, -430.0, 0.0, 40001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 1, "2030/12/17 14:59:59", 1, 41, 0.0, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", "シェフィ", 1, 0, -363.0, 0.0, 41001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 41, 0.0, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", "ペコリーヌ", 1, 0, -363.0, 0.0, 41002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 41, 0.0, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", "キャル", 1, 0, -363.0, 0.0, 41003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 41, 0.0, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", "コッコロ", 1, 0, -363.0, 0.0, 41004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 42, 0.0, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", "コッコロ", 1, 0, -416.5, 0.0, 42001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 106401, 1, "2030/12/17 14:59:59", 1, 42, 0.0, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", "シェフィ", 1, 0, -416.5, 0.0, 42002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 42, 0.0, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", "ペコリーヌ", 1, 0, -416.5, 0.0, 42003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 42, 0.0, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", "キャル", 1, 0, -416.5, 0.0, 42004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105801, 1, "2030/12/17 14:59:59", 1, 43, 0.0, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", "ペコリーヌ", 1, 0, -363.0, 0.0, 43001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 105901, 1, "2030/12/17 14:59:59", 1, 43, 0.0, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", "コッコロ", 1, 0, -363.0, 0.0, 43002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 106001, 1, "2030/12/17 14:59:59", 1, 43, 0.0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "キャル", 1, 0, -363.0, 0.0, 43003);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 123001, 1, "2030/12/17 14:59:59", 1, 44, 0.0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "アメス", 1, 0, -416.5, 0.0, 43004);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 123001, 1, "2030/12/17 14:59:59", 1, 44, 0.0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", "アメス", 2, 0, -416.5, 0.0, 43005);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 123001, 1, "2030/12/17 14:59:59", 2, 45, 0.0, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "アメス", 3, 0, -416.5, 5.79, 43006);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 123001, 1, "2030/12/17 14:59:59", 1, 46, 0.0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", "アメス", 1, 0, -371.5, 0.0, 46001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 104901, 2, "2030/12/17 14:59:59", 2, 47, 0.0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", "シズル", 1, 0, -416.5, 0.0, 47001);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 101101, 1, "2030/12/17 14:59:59", 2, 47, 0.0, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", "リノ", 1, 0, -416.5, 9.32, 47002);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 104901, 2, "2030/12/17 14:59:59", 2, 48, 0.0, "", "シズル", 0, 0, -470.0, 0.0, 48001);
